// inside ClanContext.js
const updateClan = (id, updatedClan) => {
  setClans(prev => prev.map(c => (c.id === id ? updatedClan : c)));
};

const deleteClan = (id) => {
  setClans(prev => prev.filter(c => c.id !== id));
};
